// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCampusIdentity
 * @dev Handles KYC, time-based access control, and tournament prize pools.
 */
contract SmartCampusIdentity is Ownable {

    struct IdentityRecord {
        string userId;
        string kycHash;
        uint256 verifiedAt;
    }

    struct AccessPermission {
        address user;
        string resourceId;
        uint256 expiry;
    }

    mapping(address => IdentityRecord) public identities;
    mapping(bytes32 => AccessPermission) public permissions;
    mapping(string => uint256) public tournamentPrizes;

    event KYCVerified(address indexed user, string kycHash);
    event AccessGranted(address indexed user, string resourceId, uint256 expiry);
    event TournamentFunded(string indexed tournamentId, uint256 amount);
    event TournamentPrizeDistributed(string indexed tournamentId, address indexed winner, uint256 amount);

    constructor(address initialOwner) Ownable(initialOwner) {}

    // --- KYC ---
    function verifyKYC(address user, string calldata userId, string calldata kycHash) external onlyOwner {
        identities[user] = IdentityRecord(userId, kycHash, block.timestamp);
        emit KYCVerified(user, kycHash);
    }

    // --- Access Control ---
    function grantAccess(address user, string calldata resourceId, uint256 duration) external onlyOwner {
        bytes32 key = keccak256(abi.encodePacked(user, resourceId));
        uint256 expiry = block.timestamp + duration;
        permissions[key] = AccessPermission(user, resourceId, expiry);
        emit AccessGranted(user, resourceId, expiry);
    }

    function hasAccess(address user, string calldata resourceId) external view returns (bool) {
        bytes32 key = keccak256(abi.encodePacked(user, resourceId));
        return permissions[key].expiry > block.timestamp;
    }

    // --- Gaming Tournaments ---
    function fundTournament(string calldata tournamentId) external payable {
        tournamentPrizes[tournamentId] += msg.value;
        emit TournamentFunded(tournamentId, msg.value);
    }

    function distributeTournamentPrize(string calldata tournamentId, address winner) external onlyOwner {
        uint256 amount = tournamentPrizes[tournamentId];
        require(amount > 0, "No prize pool");
        tournamentPrizes[tournamentId] = 0;
        (bool success, ) = payable(winner).call{value: amount}("");
        require(success, "Prize distribution failed");
        emit TournamentPrizeDistributed(tournamentId, winner, amount);
    }
}

contracts/SmartCampusLearning.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCampusLearning
 * @dev Handles pay-per-module, coaching, and tuition payments.
 */
contract SmartCampusLearning is Ownable {

    struct ModuleAccess {
        string moduleId;
        address student;
        uint256 payment;
    }

    struct CoachingSession {
        string sessionId;
        address tutor;
        uint256 fee;
        bool isReleased;
    }

    mapping(string => mapping(address => bool)) public hasAccess;
    mapping(string => CoachingSession) public sessions;

    event ModulePurchased(string indexed moduleId, address indexed student, uint256 amount);
    event CoachingFunded(string indexed sessionId, address indexed tutor, uint256 amount);
    event CoachingPaymentReleased(string indexed sessionId, address indexed tutor, uint256 amount);

    constructor(address initialOwner) Ownable(initialOwner) {}

    // --- Pay-per-Lesson ---
    function purchaseModule(string calldata moduleId) external payable {
        require(msg.value > 0, "Payment must be > 0");
        hasAccess[moduleId][msg.sender] = true;
        emit ModulePurchased(moduleId, msg.sender, msg.value);
    }

    // --- Coaching/Tuition Escrow ---
    function fundCoaching(string calldata sessionId, address tutor) external payable {
        require(msg.value > 0, "Fee must be > 0");
        sessions[sessionId] = CoachingSession(sessionId, tutor, msg.value, false);
        emit CoachingFunded(sessionId, tutor, msg.value);
    }

    function releaseCoachingPayment(string calldata sessionId) external onlyOwner {
        CoachingSession storage s = sessions[sessionId];
        require(s.fee > 0 && !s.isReleased, "Invalid session state");
        s.isReleased = true;
        (bool success, ) = payable(s.tutor).call{value: s.fee}("");
        require(success, "Coaching payment failed");
        emit CoachingPaymentReleased(sessionId, s.tutor, s.fee);
    }

    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        (bool success, ) = payable(owner()).call{value: balance}("");
        require(success, "Withdrawal failed");
    }
}

contracts/SmartCampusWorkplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCampusWorkplace
 * @dev Handles faculty payroll, internships, skill verification, and campus marketplace.
 */
contract SmartCampusWorkplace is Ownable {

    struct Internship {
        string internshipId;
        address student;
        string company;
        bool completed;
        string certificateHash;
    }

    struct JobOffer {
        string jobId;
        address employer;
        uint256 budget;
        bool isEscrowed;
        bool isCompleted;
    }

    mapping(string => Internship) public internships;
    mapping(string => JobOffer) public jobs;
    mapping(address => mapping(string => bool)) public verifiedSkills; // student => skillBadge => verified

    event SalaryBonusReleased(address indexed faculty, uint256 amount, string reason);
    event InternshipCompleted(string indexed internshipId, address student, string certificateHash);
    event SkillVerified(address indexed student, string skillBadge);
    event JobEscrowed(string indexed jobId, uint256 amount);
    event JobPaymentReleased(string indexed jobId, address indexed freelancer, uint256 amount);

    constructor(address initialOwner) Ownable(initialOwner) {}

    // --- Payroll & Bonuses ---
    function releaseBonus(address faculty, string calldata reason) external payable onlyOwner {
        require(msg.value > 0, "Bonus amount must be > 0");
        (bool success, ) = payable(faculty).call{value: msg.value}("");
        require(success, "Bonus distribution failed");
        emit SalaryBonusReleased(faculty, msg.value, reason);
    }

    // --- Internships ---
    function registerInternship(string calldata internshipId, address student, string calldata company) external onlyOwner {
        internships[internshipId] = Internship(internshipId, student, company, false, "");
    }

    function completeInternship(string calldata internshipId, string calldata certificateHash) external onlyOwner {
        Internship storage i = internships[internshipId];
        i.completed = true;
        i.certificateHash = certificateHash;
        emit InternshipCompleted(internshipId, i.student, certificateHash);
    }

    // --- Skills ---
    function verifySkill(address student, string calldata skillBadge) external onlyOwner {
        verifiedSkills[student][skillBadge] = true;
        emit SkillVerified(student, skillBadge);
    }

    // --- Marketplace Escrow ---
    function postJob(string calldata jobId) external payable {
        require(msg.value > 0, "Escrow amount must be > 0");
        jobs[jobId] = JobOffer(jobId, msg.sender, msg.value, true, false);
        emit JobEscrowed(jobId, msg.value);
    }

    function releaseJobPayment(string calldata jobId, address freelancer) external onlyOwner {
        JobOffer storage j = jobs[jobId];
        require(j.isEscrowed && !j.isCompleted, "Invalid job state");
        j.isCompleted = true;
        (bool success, ) = payable(freelancer).call{value: j.budget}("");
        require(success, "Payment release failed");
        emit JobPaymentReleased(jobId, freelancer, j.budget);
    }
}

